<script type="ts">import { Tabs, TabList, TabPanel, Tab, Modal, } from "../Components/components.js";
import FileExplorer from "../Components/FileExplorer/FileExplorer.svelte";
import DocumentEditor from "../Components/DocumentEditor.svelte";
import Panel from "../Components/Panel.svelte";
import PageViewer from "../Components/PageViewer.svelte";
import ASTViewer from "../Components/ASTViewer.svelte";
import { moduleStore } from "../Services/module.js";
import CreateDomain from "../Forms/CreateDomain.svelte";
import { get } from "./../Services/http";
let timeout;
let module;
let svgUrl;
let componentUrl;
let htmlUrl;
const generateUrls = () => {
    if (!module || !module.namespace)
        return;
    var ns = module.namespace;
    svgUrl = `/documents/${ns}/data.svg?timestamp=${new Date().getMilliseconds()}`;
    componentUrl = `/documents/${ns}/components.svg?timestamp=${new Date().getMilliseconds()}`;
    htmlUrl = `/documents/${ns}/page.html?timestamp=${new Date().getMilliseconds()}`;
};
moduleStore.subscribe((s) => {
    if (timeout)
        clearTimeout(timeout);
    timeout = setTimeout(() => {
        if (!s || !s.selectedModule || !s.modules) {
            svgUrl = undefined;
            componentUrl = undefined;
            htmlUrl = undefined;
            return;
        }
        module = s.modules[s.selectedModule];
        generateUrls();
    }, 2000);
});
let showCreateDomain = false;
</script>

<div class="container">
    <div class="file-explorer--container">
        <FileExplorer />
    </div>
    <div class="document-editor">
        <div>
            <DocumentEditor />
        </div>
    </div>
    <div class="page-viewer">
        <Tabs>
            <TabList>
                <Tab>Architecture</Tab>
                <Tab>Data Model</Tab>
                <Tab>AST</Tab>
                <Tab>Document</Tab>
            </TabList>

            <TabPanel>
                <Panel>
                    {#if svgUrl}
                        <img alt="svg" src={componentUrl} />
                    {/if}
                </Panel>
            </TabPanel>

            <TabPanel>
                <Panel>
                    {#if componentUrl}
                        <img alt="svg" src={svgUrl} />
                    {/if}
                </Panel>
            </TabPanel>

            <TabPanel>
                <Panel
                    style="margin-top: 3rem; height: calc(100% - 3rem); overflow: hidden; padding: 0;">
                    <ASTViewer />
                </Panel>
            </TabPanel>

            <TabPanel>
                {#if htmlUrl}
                    <Panel
                        style="background:lightgray; height: calc(100% - 3rem); margin-top: 3rem; padding: 0; padding-top: 2rem;">
                        <!-- <PageViewer url={htmlUrl} /> -->
                        <iframe
                            class="html-iframe"
                            src={htmlUrl}
                            title="Page" />
                    </Panel>
                {/if}
            </TabPanel>
        </Tabs>
    </div>

    <Modal title="Create Domain" show={showCreateDomain}>
        <CreateDomain />
    </Modal>
</div>

